import React, { Component } from 'react';
import { View, Text, TouchableOpacity, StyleSheet } from 'react-native';
import { formatTime, getUserName } from '../utils/format';

export default class MessageItem extends Component {
  render() {
    var { message, usersMap, currentUserId, onLongPress, onThreadPress } = this.props;

    if (message.subtype === 'channel_join' || message.subtype === 'channel_leave' ||
        message.subtype === 'group_join' || message.subtype === 'group_leave') {
      return (
        <View style={styles.systemMsg}>
          <Text style={styles.systemText}>{message.text}</Text>
        </View>
      );
    }

    var userName = message.username || getUserName(message.user, usersMap);
    var isOwn = message.user === currentUserId;
    var time = formatTime(message.ts);
    var edited = message.edited ? ' (edited)' : '';
    var threadCount = message.reply_count || 0;

    var reactions = message.reactions || [];

    return (
      <TouchableOpacity
        style={styles.container}
        onLongPress={function () { onLongPress && onLongPress(message); }}
        activeOpacity={0.7}
      >
        <View style={styles.header}>
          <Text style={[styles.userName, isOwn && styles.ownName]}>{userName}</Text>
          <Text style={styles.time}>{time}{edited}</Text>
        </View>
        <Text style={styles.text}>{message.text}</Text>
        {message.files && message.files.length > 0 ? (
          <View style={styles.fileContainer}>
            {message.files.map(function (f, i) {
              return (
                <Text key={i} style={styles.fileName}>
                  [File: {f.name || f.title || 'attachment'}]
                </Text>
              );
            })}
          </View>
        ) : null}
        {reactions.length > 0 ? (
          <View style={styles.reactionsRow}>
            {reactions.map(function (r, i) {
              return (
                <View key={i} style={styles.reactionBadge}>
                  <Text style={styles.reactionText}>:{r.name}: {r.count}</Text>
                </View>
              );
            })}
          </View>
        ) : null}
        {threadCount > 0 ? (
          <TouchableOpacity
            style={styles.threadLink}
            onPress={function () { onThreadPress && onThreadPress(message); }}
          >
            <Text style={styles.threadText}>
              {threadCount} {threadCount === 1 ? 'reply' : 'replies'}
            </Text>
          </TouchableOpacity>
        ) : null}
      </TouchableOpacity>
    );
  }
}

var styles = StyleSheet.create({
  container: {
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderBottomWidth: StyleSheet.hairlineWidth,
    borderBottomColor: '#1a2338',
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    marginBottom: 2,
  },
  userName: {
    color: '#ccccdd',
    fontSize: 13,
    fontWeight: 'bold',
    marginRight: 8,
  },
  ownName: {
    color: '#4A90D9',
  },
  time: {
    color: '#555577',
    fontSize: 10,
  },
  text: {
    color: '#ddddee',
    fontSize: 14,
    lineHeight: 20,
  },
  systemMsg: {
    paddingHorizontal: 12,
    paddingVertical: 4,
    alignItems: 'center',
  },
  systemText: {
    color: '#555577',
    fontSize: 11,
    fontStyle: 'italic',
  },
  fileContainer: {
    marginTop: 4,
  },
  fileName: {
    color: '#4A90D9',
    fontSize: 12,
  },
  reactionsRow: {
    flexDirection: 'row',
    flexWrap: 'wrap',
    marginTop: 4,
  },
  reactionBadge: {
    backgroundColor: '#1a2338',
    borderRadius: 10,
    paddingHorizontal: 8,
    paddingVertical: 2,
    marginRight: 4,
    marginBottom: 2,
    borderWidth: 1,
    borderColor: '#2a2a4e',
  },
  reactionText: {
    color: '#aaaacc',
    fontSize: 11,
  },
  threadLink: {
    marginTop: 4,
  },
  threadText: {
    color: '#4A90D9',
    fontSize: 12,
  },
});
